import { classNames } from ':helpers/classnames';
import React, { Fragment, useCallback, useEffect, useState } from 'react';

import type { RenderFn, TableRowItem, TableRowsProps } from './TableRows.types';

/**
 * @name TableRows Компонент для отображения вложенных строк таблицы
 * @prop { boolean } hidden Скрытие верстки
 * @prop { TableRowItem[] } items Данные для отображения
 * @prop { number } depth Глубина дерева
 * @prop { RenderFn } render Функция рендеринга
 * @prop { string } className Наименование класса
 * @prop { boolean } hidden Флаг отображения таблицы
 * @prop { boolean } expandedOnOpen Открываться вначале
 */
export const TableRows = ({ hidden, items, depth = 0, render, className, expandedOnOpen = false }: TableRowsProps) => {
	const [expandedMap, setExpandedMap] = useState<Record<string | number, boolean>>({});
	const onClick = useCallback(
		(id: string | number) => () => {
			setExpandedMap({ ...expandedMap, [id]: !expandedMap[id] });
		},
		[expandedMap],
	);

	useEffect(() => {
		if (!expandedOnOpen) {
			return;
		}

		setExpandedMap(items?.reduce((result, item) => ({ ...result, [item.id]: expandedOnOpen }), {}));
	}, [items, expandedOnOpen]);

	if (hidden) {
		return null;
	}

	return (
		<>
			{items?.map((item: TableRowItem, currentIndex: number) => {
				const hasChildren = item?.children && item?.children?.length > 0;
				const isExpanded = Boolean(expandedMap[item.id]);

				return (
					<Fragment key={item.id}>
						{render({
							isExpanded,
							item,
							hasChildren,
							onClick,
							depth,
							className,
						} as RenderFn)}

						{isExpanded && (
							<TableRows
								key={item.id}
								items={item?.children}
								depth={depth + 1}
								data-testid="TableRows"
								expandedOnOpen={expandedOnOpen}
								render={render.bind({
									isExpanded,
									item,
									hasChildren: item?.children?.length > 0,
									onClick,
									depth: depth + 1,
									className,
									currentIndex,
								})}
								className={classNames(!hasChildren && 'dsb_table-rows__nested')}
							/>
						)}
					</Fragment>
				);
			})}
		</>
	);
};
